def _logo_data_uri() -> str:
    '''兼容源码、PyInstaller目录版和单文件模式查找Logo。'''
    candidates = [
        Path(__file__).resolve().parent.parent / 'logo.png',
        Path(sys.executable).resolve().parent / 'logo.png',
        Path(sys.executable).resolve().parent / '_internal' / 'logo.png',
    ]
    meipass = getattr(sys, '_MEIPASS', None)
    if meipass:
        candidates.insert(0, Path(meipass) / 'logo.png')
    for logo_path in candidates:
        try:
            if logo_path.is_file():
                return 'data:image/png;base64,' + base64.b64encode(logo_path.read_bytes()).decode('ascii')
        except Exception:
            continue
    fallback_svg = '<svg xmlns="http://www.w3.org/2000/svg" width="128" height="128"><rect width="128" height="128" rx="24" fill="#1677ff"/><text x="64" y="82" text-anchor="middle" font-family="Microsoft YaHei,Arial" font-size="62" font-weight="700" fill="white">新</text></svg>'
    return 'data:image/svg+xml;base64,' + base64.b64encode(fallback_svg.encode('utf-8')).decode('ascii')


def _cleanup_old_map_files(max_age_seconds: int = 21600) -> None:
    '''清理已退出地图窗口留下的临时HTML/点位文件，避免二次打开积累锁定资源。'''
    out_dir = Path(tempfile.gettempdir()) / 'xinkongyu_gps_map'
    if not out_dir.exists():
        return None
    cutoff = time.time() - max_age_seconds
    for path in out_dir.glob('gps_map_*'):
        try:
            if path.is_file() and path.stat().st_mtime < cutoff:
                path.unlink(missing_ok=True)
        except Exception:
            continue
    return None


